// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Enroll a tunnex-node agent with a join token
	// (POST /api/v1/agent/enroll)
	EnrollAgent(w http.ResponseWriter, r *http.Request)
	// Mint a one-time CLI authorization code (browser leg)
	// (POST /api/v1/auth/cli/authorize)
	CliAuthorize(w http.ResponseWriter, r *http.Request)
	// List the caller's CLI credentials (metadata only — never tokens)
	// (GET /api/v1/auth/cli/credentials)
	ListCliCredentials(w http.ResponseWriter, r *http.Request)
	// Revoke one of the caller's CLI credentials (immediate)
	// (DELETE /api/v1/auth/cli/credentials/{credentialId})
	RevokeCliCredential(w http.ResponseWriter, r *http.Request, credentialId openapi_types.UUID)
	// Start the device-code fallback (browserless hosts)
	// (POST /api/v1/auth/cli/device)
	CliDeviceStart(w http.ResponseWriter, r *http.Request)
	// Approve a device-code login (browser leg)
	// (POST /api/v1/auth/cli/device/approve)
	CliDeviceApprove(w http.ResponseWriter, r *http.Request)
	// Poll for the device-flow credential
	// (POST /api/v1/auth/cli/device/token)
	CliDeviceToken(w http.ResponseWriter, r *http.Request)
	// Exchange a one-time code (+ PKCE verifier) for a CLI credential
	// (POST /api/v1/auth/cli/token)
	CliToken(w http.ResponseWriter, r *http.Request)
	// Accept an invitation
	// (POST /api/v1/auth/invitations/accept)
	AcceptInvitation(w http.ResponseWriter, r *http.Request)
	// Verify credentials
	// (POST /api/v1/auth/login)
	Login(w http.ResponseWriter, r *http.Request)
	// Revoke the current session
	// (POST /api/v1/auth/logout)
	Logout(w http.ResponseWriter, r *http.Request)
	// The current authenticated user
	// (GET /api/v1/auth/me)
	CurrentUser(w http.ResponseWriter, r *http.Request)
	// Request a password-reset email
	// (POST /api/v1/auth/password-reset)
	RequestPasswordReset(w http.ResponseWriter, r *http.Request)
	// Set a new password using a reset token
	// (POST /api/v1/auth/password-reset/confirm)
	ConfirmPasswordReset(w http.ResponseWriter, r *http.Request)
	// Create a local account (sends a verification email)
	// (POST /api/v1/auth/signup)
	Signup(w http.ResponseWriter, r *http.Request)
	// SSO callback (enterprise)
	// (GET /api/v1/auth/sso/{provider}/callback)
	SsoCallback(w http.ResponseWriter, r *http.Request, provider SsoCallbackParamsProvider, params SsoCallbackParams)
	// Begin an SSO login (enterprise)
	// (GET /api/v1/auth/sso/{provider}/start)
	StartSsoLogin(w http.ResponseWriter, r *http.Request, provider StartSsoLoginParamsProvider, params StartSsoLoginParams)
	// Verify an email address with a token
	// (POST /api/v1/auth/verify-email)
	VerifyEmail(w http.ResponseWriter, r *http.Request)
	// Resend the current user's email-verification link
	// (POST /api/v1/auth/verify-email/resend)
	ResendVerification(w http.ResponseWriter, r *http.Request)
	// Public deployment metadata (edition, enabled SSO providers)
	// (GET /api/v1/meta)
	GetMeta(w http.ResponseWriter, r *http.Request)
	// List organizations
	// (GET /api/v1/organizations)
	ListOrganizations(w http.ResponseWriter, r *http.Request)
	// Create an organization
	// (POST /api/v1/organizations)
	CreateOrganization(w http.ResponseWriter, r *http.Request)
	// Soft-delete an organization
	// (DELETE /api/v1/organizations/{orgId})
	DeleteOrganization(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Get an organization
	// (GET /api/v1/organizations/{orgId})
	GetOrganization(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Update organization settings (name only; slug is immutable)
	// (PATCH /api/v1/organizations/{orgId})
	UpdateOrganization(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// The org's Zero Trust access/flow events — keyset-paginated (enterprise, read-only)
	// (GET /api/v1/organizations/{orgId}/access-events)
	ListAccessEvents(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, params ListAccessEventsParams)
	// Export the org's access events as the raw JSONL source-of-truth stream (enterprise)
	// (GET /api/v1/organizations/{orgId}/access-events/export)
	ExportAccessEvents(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Access-log subsystem health — JSONL-stream degradation + retention sweep (enterprise)
	// (GET /api/v1/organizations/{orgId}/access-log/health)
	GetAccessLogHealth(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// The org's audit log — filterable, keyset-paginated (read-only)
	// (GET /api/v1/organizations/{orgId}/audit-logs)
	ListAuditLogs(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, params ListAuditLogsParams)
	// Get the org device-approval mode (enterprise)
	// (GET /api/v1/organizations/{orgId}/device-approval)
	GetDeviceApproval(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Set the org device-approval mode — enabling gates new enrollments (enterprise)
	// (PUT /api/v1/organizations/{orgId}/device-approval)
	SetDeviceApproval(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// List devices (own devices for members; all for admins)
	// (GET /api/v1/organizations/{orgId}/devices)
	ListDevices(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Create a device/peer bound to the owning user
	// (POST /api/v1/organizations/{orgId}/devices)
	CreateDevice(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// The device-approval queue (enterprise)
	// (GET /api/v1/organizations/{orgId}/devices/pending)
	ListPendingDevices(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Approve a pending device (peer + grants land org-wide within seconds, enterprise)
	// (POST /api/v1/organizations/{orgId}/devices/{deviceId}/approve)
	ApproveDevice(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, deviceId openapi_types.UUID)
	// Reject a pending device (revoked, tunnel address freed, enterprise)
	// (POST /api/v1/organizations/{orgId}/devices/{deviceId}/reject)
	RejectDevice(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, deviceId openapi_types.UUID)
	// Revoke a device (peer removed from the gateway within seconds)
	// (POST /api/v1/organizations/{orgId}/devices/{deviceId}/revoke)
	RevokeDevice(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, deviceId openapi_types.UUID)
	// Claim an email domain for capture (enterprise)
	// (POST /api/v1/organizations/{orgId}/domains)
	CreateDomainClaim(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Verify a claimed domain via its DNS TXT record (enterprise)
	// (POST /api/v1/organizations/{orgId}/domains/verify)
	VerifyDomainClaim(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// List user-groups (enterprise)
	// (GET /api/v1/organizations/{orgId}/groups)
	ListGroups(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Create a user-group (enterprise)
	// (POST /api/v1/organizations/{orgId}/groups)
	CreateGroup(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Delete a user-group (enterprise)
	// (DELETE /api/v1/organizations/{orgId}/groups/{groupId})
	DeleteGroup(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, groupId openapi_types.UUID)
	// Rename / re-describe a user-group (enterprise)
	// (PATCH /api/v1/organizations/{orgId}/groups/{groupId})
	UpdateGroup(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, groupId openapi_types.UUID)
	// List a group's members (enterprise)
	// (GET /api/v1/organizations/{orgId}/groups/{groupId}/members)
	ListGroupMembers(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, groupId openapi_types.UUID)
	// Add a member to a group (enterprise)
	// (POST /api/v1/organizations/{orgId}/groups/{groupId}/members)
	AddGroupMember(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, groupId openapi_types.UUID)
	// Remove a member from a group (enterprise)
	// (DELETE /api/v1/organizations/{orgId}/groups/{groupId}/members/{userId})
	RemoveGroupMember(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, groupId openapi_types.UUID, userId openapi_types.UUID)
	// Invite a user to the organization
	// (POST /api/v1/organizations/{orgId}/invitations)
	CreateInvitation(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Resend an invitation (new token, old invalidated)
	// (POST /api/v1/organizations/{orgId}/invitations/resend)
	ResendInvitation(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Revoke a pending invitation
	// (POST /api/v1/organizations/{orgId}/invitations/revoke)
	RevokeInvitation(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// List the organization's members (roster incl. deactivated)
	// (GET /api/v1/organizations/{orgId}/members)
	ListMembers(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Deactivate a member's account (freezes access, revokes sessions)
	// (POST /api/v1/organizations/{orgId}/members/{userId}/deactivate)
	DeactivateMember(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, userId openapi_types.UUID)
	// Reactivate a deactivated member
	// (POST /api/v1/organizations/{orgId}/members/{userId}/reactivate)
	ReactivateMember(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, userId openapi_types.UUID)
	// Change a member's role (RBAC-gated; refuses demoting the last owner)
	// (PUT /api/v1/organizations/{orgId}/members/{userId}/role)
	ChangeMemberRole(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, userId openapi_types.UUID)
	// List enrolled nodes
	// (GET /api/v1/organizations/{orgId}/nodes)
	ListNodes(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Issue a single-use node join token
	// (POST /api/v1/organizations/{orgId}/nodes/join-token)
	IssueJoinToken(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Revoke a node (renewal will be refused)
	// (POST /api/v1/organizations/{orgId}/nodes/{nodeId}/revoke)
	RevokeNode(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, nodeId openapi_types.UUID)
	// Dashboard overview — counts + recent activity
	// (GET /api/v1/organizations/{orgId}/overview)
	GetOrgOverview(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// List allow-rules (enterprise)
	// (GET /api/v1/organizations/{orgId}/policies)
	ListPolicyRules(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Create an allow-rule (enterprise)
	// (POST /api/v1/organizations/{orgId}/policies)
	CreatePolicyRule(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Delete an allow-rule (enterprise)
	// (DELETE /api/v1/organizations/{orgId}/policies/{ruleId})
	DeletePolicyRule(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, ruleId openapi_types.UUID)
	// Resize the org's WireGuard address pool (grow-superset or shrink-subset)
	// (PUT /api/v1/organizations/{orgId}/pool-cidr)
	ResizePool(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// List policy resources (enterprise)
	// (GET /api/v1/organizations/{orgId}/resources)
	ListResources(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Create a policy resource (enterprise)
	// (POST /api/v1/organizations/{orgId}/resources)
	CreateResource(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Delete a policy resource (enterprise)
	// (DELETE /api/v1/organizations/{orgId}/resources/{resourceId})
	DeleteResource(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, resourceId openapi_types.UUID)
	// Update a policy resource (enterprise)
	// (PATCH /api/v1/organizations/{orgId}/resources/{resourceId})
	UpdateResource(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, resourceId openapi_types.UUID)
	// Read an SSO provider's config (enterprise) — never returns the secret
	// (GET /api/v1/organizations/{orgId}/sso/{provider})
	GetSsoConfig(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, provider string)
	// Configure an SSO provider for an organization (enterprise)
	// (PUT /api/v1/organizations/{orgId}/sso/{provider})
	SetSsoConfig(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID, provider string)
	// Get the org enforcement mode (enterprise)
	// (GET /api/v1/organizations/{orgId}/zero-trust-mode)
	GetZeroTrustMode(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Set the org enforcement mode — enabling turns on default-deny (enterprise)
	// (PUT /api/v1/organizations/{orgId}/zero-trust-mode)
	SetZeroTrustMode(w http.ResponseWriter, r *http.Request, orgId openapi_types.UUID)
	// Liveness probe
	// (GET /healthz)
	GetHealth(w http.ResponseWriter, r *http.Request)
}

